mapper.select:
/* com.shop.mapper.frontWeb.display.selectProductInfoListForEnumPaging */ SELECT PR.ID AS prodId , PR.PROD_NM AS prodNm , PR.SELL_AMT AS sellAmt , PR.DISCOUNT_RATE AS discountRate , FD.SYS_FILE_NM AS sysFileNm FROM TB_PRODUCT PR LEFT JOIN TB_FILE_DET FD ON FD.FILE_ID = PR.REP_FILE_ID AND FD.DEL_YN = 'N' AND FD.FILE_SEQ = 1
AND PR.DEL_YN = 'N' /* 관리자가 카테고리와 연결한 상품만 조회 */ AND EXISTS ( SELECT CP.ID FROM TB_CATEGORY_PRODUCT CP JOIN TB_PARTNER_CODE PC ON PC.PARTNER_ID = #{filter.partnerId} AND PC.CODE_UPPER = 'P0001' AND PC.DEL_YN = 'N' AND PC.ID = CP.CATEGORY_ID WHERE CP.PRODUCT_ID = PR.ID
AND PC.CODE_CD = #{filter.categoryCd}
)
AND PR.ID > #{filter.lastProdId}
ORDER BY PR.ID LIMIT #{pageRowCount} + 1;
